sys_variable_value.value:
(function (outputs, steps, params, stepResult, assertEqual) {

	var bLog = false;
	var _gtSecurity = new global.GlobalToolsSecurity();
	var _gtATF = new global.GlobalToolsATF('GlobalToolsSecurity', _gtSecurity, bLog, outputs, steps, params, stepResult, assertEqual);
	var grAdmin = _gtATF.getRecord('sys_user', 'user_name=admin'); // known demo user
	var sAdminRoleId = _gtSecurity.getRoleIdFromName('admin'); // known role sys_id

	// getRoleIdFromName
	_gtATF.runATF('getRoleIdFromName', /^[a-f0-9]{32}$/, 'admin'); // valid name returns a 32 char sys_id
	_gtATF.runATF('getRoleIdFromName', false, 'this_role_does_not_exist_xyz'); // invalid name returns false
	_gtATF.runATF('getRoleIdFromName', false); // missing name returns false

	// isValidRole
	_gtATF.runATF('isValidRole', true, 'admin'); // valid by name
	_gtATF.runATF('isValidRole', true, sAdminRoleId); // valid by sys_id
	_gtATF.runATF('isValidRole', false, 'na'); // invalid role
	_gtATF.runATF('isValidRole', false); // missing role

	// getUsersRoles
	_gtATF.runATF('getUsersRoles', true, grAdmin, 'boolean'); // admin has at least one role
	_gtATF.runATF('getUsersRoles', '>0', grAdmin, 'name'); // name array is not empty
	_gtATF.runATF('getUsersRoles', '>0', grAdmin, 'id'); // id array is not empty
	_gtATF.runATF('getUsersRoles', 0, '00000000000000000000000000000000', 'name'); // unknown user returns empty array
	_gtATF.runATF('getUsersRoles', false, '00000000000000000000000000000000', 'boolean'); // unknown user is false in boolean mode

	// checkParentAccessResult - hierarchy of incident always contains task
	_gtATF.runATF('checkParentAccessResult', true, 'incident', 'CRUD', { task: { CRUD: 'CRUD' } }); // parent with same access is covered
	_gtATF.runATF('checkParentAccessResult', false, 'incident', 'CRUD', { task: { CRUD: 'R' } }); // parent with different access is not covered
	_gtATF.runATF('checkParentAccessResult', false, 'incident', 'CRUD', {}); // no parent access stored is not covered
	// generateAccessReport - error paths only (happy path needs Access Analyzer impersonation, not available in ATF)

	_gtATF.runATF('generateAccessReport', { sError: 'Role is invalid: na' }, 'na'); // invalid role
	_gtATF.runATF('generateAccessReport', { sError: 'Table Query is invalid: na' }, 'admin', 'na'); // invalid table query
	
	// generateAccessAnalyzerReport - deterministic validation error paths only
	_gtATF.runATF('generateAccessAnalyzerReport', { sError: 'Role is invalid: na' }, 'na'); // invalid role
	_gtATF.runATF('generateAccessAnalyzerReport', { sError: 'Table Query is invalid: na' }, 'admin', 'na'); // invalid table query
	return _gtATF.endATF();

})(outputs, steps, params, stepResult, assertEqual);
